import{_ as s,c as n,o as t,a8 as e}from"./chunks/framework.DMZhn_gK.js";const m="/assets/image-20260328120636991.KRf7DTuU.png",l="/assets/image-20260328100827069.CdToaz7t.png",u=JSON.parse('{"title":"有监督，无监督，半监督","description":"有监督，无监督，半监督","frontmatter":{"title":"有监督，无监督，半监督","tags":["transform","大模型训练"],"categories":["transform"],"date":"2026-3-28","description":"有监督，无监督，半监督","articleGPT":"有监督，无监督，半监督","references":[{"title":"Java","url":"https://github.com/imsyy/vitepress-theme-curve"}]},"headers":[],"relativePath":"ModelTraning/机器学习.md","filePath":"ModelTraning/机器学习.md","lastUpdated":1776154279000}'),i={name:"ModelTraning/机器学习.md"};function r(p,a,o,c,h,d){return t(),n("div",null,[...a[0]||(a[0]=[e('<h2 id="有监督-无监督-半监督-强化学习" tabindex="-1">有监督，无监督，半监督,强化学习 <a class="header-anchor" href="#有监督-无监督-半监督-强化学习" aria-label="Permalink to &quot;有监督，无监督，半监督,强化学习&quot;">​</a></h2><p><img src="'+m+'" alt="image-20260328120636991" loading="lazy"></p><h2 id="机器学习建模流程" tabindex="-1">机器学习建模流程 <a class="header-anchor" href="#机器学习建模流程" aria-label="Permalink to &quot;机器学习建模流程&quot;">​</a></h2><ol><li>获取数据</li><li>数据基本处理</li><li>特征工程</li><li>机器学习</li><li>模型评估</li></ol><h2 id="有监督学习模型训练和模型预测" tabindex="-1">有监督学习模型训练和模型预测 <a class="header-anchor" href="#有监督学习模型训练和模型预测" aria-label="Permalink to &quot;有监督学习模型训练和模型预测&quot;">​</a></h2><p><img src="'+l+'" alt="image-20260328100827069" loading="lazy"></p><h2 id="特征工程概念入门" tabindex="-1">特征工程概念入门 <a class="header-anchor" href="#特征工程概念入门" aria-label="Permalink to &quot;特征工程概念入门&quot;">​</a></h2><ol><li>特征提取</li><li>特征预处理: 特征对模型的影响，因量纲问题，有些特征对模型影响大，有些特征影响效 （归一化， 标准化）</li><li>特征降维： 将原始数据的维度降低</li><li>特征选择： 原始始数据特征很多，但是对模型训练相关是其中一个特征集合子集</li><li>特征组合： 把多个的特征合并成一个特征。一般利用乘法或加法来完成</li></ol><h2 id="拟合" tabindex="-1">拟合 <a class="header-anchor" href="#拟合" aria-label="Permalink to &quot;拟合&quot;">​</a></h2><p>欠拟合， 过拟合， 泛化</p><p>泛化： 模型在非训练集上表现好坏的能力</p><p>奥卡姆剃刀原则： 给定两个具有相同泛化误差的模型，较简单的模型比较复杂的模型更可取。</p><h2 id="knn算法简介" tabindex="-1">KNN算法简介 <a class="header-anchor" href="#knn算法简介" aria-label="Permalink to &quot;KNN算法简介&quot;">​</a></h2><p>K-近邻算法简称KNN， 算法思想为： 如果一个样本在特征空间中的k个最相似的样本中的大多数属于某一个类别，则该样本也属于这个类别</p><p>如何确定样本的相似性？</p><p>超参</p><p>KNN解决的问题有俩种一种是分类一种是回归</p><h2 id="knn分类与回归流程" tabindex="-1">KNN分类与回归流程 <a class="header-anchor" href="#knn分类与回归流程" aria-label="Permalink to &quot;KNN分类与回归流程&quot;">​</a></h2><p>分类流程</p><p>1.计算未知样本到每一个训练样本的距离 2.将训练样本根据距离大小升序排列 3.取出距离最近的K个训练样本 4.进行多数表决，统计K个样本中哪个类别的样本个数量 5.将未知的样本归属到出现次数最多的类别</p><p>回归流程</p><p>1.计算未知样本到每一个训练样本的距离 2.将训练样本根据距离大小升序排列 3.取出距离最近的K个训练样本 4.把这个K个样本的目标值计算其平均值 5.将未知的样本预测的值了</p><h2 id="k值的选择" tabindex="-1">K值的选择 <a class="header-anchor" href="#k值的选择" aria-label="Permalink to &quot;K值的选择&quot;">​</a></h2><p>K值过大会发送欠拟合（不容易被异常值影响），过小会发送过拟合</p><p>如果K=N</p><h2 id="knn算法分类api" tabindex="-1">KNN算法分类API <a class="header-anchor" href="#knn算法分类api" aria-label="Permalink to &quot;KNN算法分类API&quot;">​</a></h2><h2 id="knn算法回归api" tabindex="-1">KNN算法回归API <a class="header-anchor" href="#knn算法回归api" aria-label="Permalink to &quot;KNN算法回归API&quot;">​</a></h2><h2 id="路径方法" tabindex="-1">路径方法 <a class="header-anchor" href="#路径方法" aria-label="Permalink to &quot;路径方法&quot;">​</a></h2><h2 id="特征预处理归一化" tabindex="-1">特征预处理归一化 <a class="header-anchor" href="#特征预处理归一化" aria-label="Permalink to &quot;特征预处理归一化&quot;">​</a></h2><h2 id="特征预处理标准化" tabindex="-1">特征预处理标准化 <a class="header-anchor" href="#特征预处理标准化" aria-label="Permalink to &quot;特征预处理标准化&quot;">​</a></h2><h2 id="交叉验证" tabindex="-1">交叉验证 <a class="header-anchor" href="#交叉验证" aria-label="Permalink to &quot;交叉验证&quot;">​</a></h2><p>交叉验证是一种用于评估机器学习模型性能的统计方法，核心思想是重复地使用数据的不同子集进行训练和验证，从而更稳健地估计模型在未知数据上的表现。</p><h3 id="什么是交叉验证" tabindex="-1">什么是交叉验证？ <a class="header-anchor" href="#什么是交叉验证" aria-label="Permalink to &quot;什么是交叉验证？&quot;">​</a></h3><p>交叉验证是一种数据集的分割方法。其基本操作是将训练集划分为 <span class="katex"><span class="katex-mathml"><math><semantics><mrow><mi>n</mi></mrow><annotation encoding="application/x-tex">n</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.43056em;"></span><span class="strut bottom" style="height:0.43056em;vertical-align:0em;"></span><span class="base textstyle uncramped"><span class="mord mathit">n</span></span></span></span> 份（也称为“折”或“folds”），然后进行 <span class="katex"><span class="katex-mathml"><math><semantics><mrow><mi>n</mi></mrow><annotation encoding="application/x-tex">n</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.43056em;"></span><span class="strut bottom" style="height:0.43056em;vertical-align:0em;"></span><span class="base textstyle uncramped"><span class="mord mathit">n</span></span></span></span> 轮训练和验证：</p><ul><li>每一轮，拿其中 <strong>1 份</strong> 作为 <strong>验证集</strong>（有时也称为测试集）。</li><li>剩下的 <strong><span class="katex"><span class="katex-mathml"><math><semantics><mrow><mi>n</mi><mo>−</mo><mn>1</mn></mrow><annotation encoding="application/x-tex">n-1</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.64444em;"></span><span class="strut bottom" style="height:0.72777em;vertical-align:-0.08333em;"></span><span class="base textstyle uncramped"><span class="mord mathit">n</span><span class="mbin">−</span><span class="mord mathrm">1</span></span></span></span> 份</strong> 作为 <strong>训练集</strong>。</li><li>最终，模型会在这 <span class="katex"><span class="katex-mathml"><math><semantics><mrow><mi>n</mi></mrow><annotation encoding="application/x-tex">n</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.43056em;"></span><span class="strut bottom" style="height:0.43056em;vertical-align:0em;"></span><span class="base textstyle uncramped"><span class="mord mathit">n</span></span></span></span> 个不同的验证集上分别得到 <span class="katex"><span class="katex-mathml"><math><semantics><mrow><mi>n</mi></mrow><annotation encoding="application/x-tex">n</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.43056em;"></span><span class="strut bottom" style="height:0.43056em;vertical-align:0em;"></span><span class="base textstyle uncramped"><span class="mord mathit">n</span></span></span></span> 个性能评分。</li></ul><h3 id="交叉验证法原理-以-为例" tabindex="-1">交叉验证法原理（以 <span class="katex"><span class="katex-mathml"><math><semantics><mrow><mi>c</mi><mi>v</mi><mo>=</mo><mn>4</mn></mrow><annotation encoding="application/x-tex">cv=4</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.64444em;"></span><span class="strut bottom" style="height:0.64444em;vertical-align:0em;"></span><span class="base textstyle uncramped"><span class="mord mathit">c</span><span class="mord mathit" style="margin-right:0.03588em;">v</span><span class="mrel">=</span><span class="mord mathrm">4</span></span></span></span> 为例） <a class="header-anchor" href="#交叉验证法原理-以-为例" aria-label="Permalink to &quot;交叉验证法原理（以 $cv=4$ 为例）&quot;">​</a></h3><p>假设我们将数据集划分为 4 份（即 4 折交叉验证），流程如下：</p><ol><li><strong>第一次</strong>：把 <strong>第一份</strong> 数据做验证集，其他三份数据做训练集。</li><li><strong>第二次</strong>：把 <strong>第二份</strong> 数据做验证集，其他三份数据做训练集。</li><li><strong>第三次</strong>：把 <strong>第三份</strong> 数据做验证集，其他三份数据做训练集。</li><li><strong>第四次</strong>：把 <strong>第四份</strong> 数据做验证集，其他三份数据做训练集。</li></ol><p><strong>总结</strong>：总共训练 4 次，评估 4 次。</p><h3 id="如何计算最终得分" tabindex="-1">如何计算最终得分？ <a class="header-anchor" href="#如何计算最终得分" aria-label="Permalink to &quot;如何计算最终得分？&quot;">​</a></h3><p>使用训练集 + 验证集多次评估模型后，取这 4 次评估结果的 <strong>平均值</strong> 作为该模型的交叉验证得分。</p><blockquote><p><strong>示例计算</strong>： 假设 4 次验证的准确率分别为：80%、78%、75%、82%</p><p>交叉验证得分 = <span class="katex"><span class="katex-mathml"><math><semantics><mrow><mfrac><mrow><mn>8</mn><mn>0</mn><mi mathvariant="normal">%</mi><mo>+</mo><mn>7</mn><mn>8</mn><mi mathvariant="normal">%</mi><mo>+</mo><mn>7</mn><mn>5</mn><mi mathvariant="normal">%</mi><mo>+</mo><mn>8</mn><mn>2</mn><mi mathvariant="normal">%</mi></mrow><mrow><mn>4</mn></mrow></mfrac><mo>=</mo><mn>7</mn><mn>8</mn><mi mathvariant="normal">.</mi><mn>7</mn><mn>5</mn><mi mathvariant="normal">%</mi></mrow><annotation encoding="application/x-tex">\\frac{80\\% + 78\\% + 75\\% + 82\\%}{4} = 78.75\\%</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.9189999999999999em;"></span><span class="strut bottom" style="height:1.2639999999999998em;vertical-align:-0.345em;"></span><span class="base textstyle uncramped"><span class="mord reset-textstyle textstyle uncramped"><span class="sizing reset-size5 size5 reset-textstyle textstyle uncramped nulldelimiter"></span><span class="mfrac"><span class="vlist"><span style="top:0.345em;"><span class="fontsize-ensurer reset-size5 size5"><span style="font-size:0em;">​</span></span><span class="reset-textstyle scriptstyle cramped"><span class="mord scriptstyle cramped"><span class="mord mathrm">4</span></span></span></span><span style="top:-0.22999999999999998em;"><span class="fontsize-ensurer reset-size5 size5"><span style="font-size:0em;">​</span></span><span class="reset-textstyle textstyle uncramped frac-line"></span></span><span style="top:-0.394em;"><span class="fontsize-ensurer reset-size5 size5"><span style="font-size:0em;">​</span></span><span class="reset-textstyle scriptstyle uncramped"><span class="mord scriptstyle uncramped"><span class="mord mathrm">8</span><span class="mord mathrm">0</span><span class="mord mathrm">%</span><span class="mbin">+</span><span class="mord mathrm">7</span><span class="mord mathrm">8</span><span class="mord mathrm">%</span><span class="mbin">+</span><span class="mord mathrm">7</span><span class="mord mathrm">5</span><span class="mord mathrm">%</span><span class="mbin">+</span><span class="mord mathrm">8</span><span class="mord mathrm">2</span><span class="mord mathrm">%</span></span></span></span><span class="baseline-fix"><span class="fontsize-ensurer reset-size5 size5"><span style="font-size:0em;">​</span></span>​</span></span></span><span class="sizing reset-size5 size5 reset-textstyle textstyle uncramped nulldelimiter"></span></span><span class="mrel">=</span><span class="mord mathrm">7</span><span class="mord mathrm">8</span><span class="mord mathrm">.</span><span class="mord mathrm">7</span><span class="mord mathrm">5</span><span class="mord mathrm">%</span></span></span></span></p></blockquote><h3 id="模型选择与最终评估" tabindex="-1">模型选择与最终评估 <a class="header-anchor" href="#模型选择与最终评估" aria-label="Permalink to &quot;模型选择与最终评估&quot;">​</a></h3><p>交叉验证常用于 <strong>模型选择</strong>（例如选择 KNN 中的 <span class="katex"><span class="katex-mathml"><math><semantics><mrow><mi>k</mi></mrow><annotation encoding="application/x-tex">k</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.69444em;"></span><span class="strut bottom" style="height:0.69444em;vertical-align:0em;"></span><span class="base textstyle uncramped"><span class="mord mathit" style="margin-right:0.03148em;">k</span></span></span></span> 值）：</p><ol><li><strong>比较不同模型</strong>：例如，分别对 <span class="katex"><span class="katex-mathml"><math><semantics><mrow><mi>k</mi><mo>=</mo><mn>3</mn></mrow><annotation encoding="application/x-tex">k=3</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.69444em;"></span><span class="strut bottom" style="height:0.69444em;vertical-align:0em;"></span><span class="base textstyle uncramped"><span class="mord mathit" style="margin-right:0.03148em;">k</span><span class="mrel">=</span><span class="mord mathrm">3</span></span></span></span>、<span class="katex"><span class="katex-mathml"><math><semantics><mrow><mi>k</mi><mo>=</mo><mn>5</mn></mrow><annotation encoding="application/x-tex">k=5</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.69444em;"></span><span class="strut bottom" style="height:0.69444em;vertical-align:0em;"></span><span class="base textstyle uncramped"><span class="mord mathit" style="margin-right:0.03148em;">k</span><span class="mrel">=</span><span class="mord mathrm">5</span></span></span></span>、<span class="katex"><span class="katex-mathml"><math><semantics><mrow><mi>k</mi><mo>=</mo><mn>7</mn></mrow><annotation encoding="application/x-tex">k=7</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.69444em;"></span><span class="strut bottom" style="height:0.69444em;vertical-align:0em;"></span><span class="base textstyle uncramped"><span class="mord mathit" style="margin-right:0.03148em;">k</span><span class="mrel">=</span><span class="mord mathrm">7</span></span></span></span> 的 KNN 模型进行 4 折交叉验证，计算各自的平均得分。</li><li><strong>选择最优模型</strong>：假设 <span class="katex"><span class="katex-mathml"><math><semantics><mrow><mi>k</mi><mo>=</mo><mn>5</mn></mrow><annotation encoding="application/x-tex">k=5</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.69444em;"></span><span class="strut bottom" style="height:0.69444em;vertical-align:0em;"></span><span class="base textstyle uncramped"><span class="mord mathit" style="margin-right:0.03148em;">k</span><span class="mrel">=</span><span class="mord mathrm">5</span></span></span></span> 的模型平均得分最高。</li><li><strong>最终训练</strong>：使用 <strong>全部训练数据</strong>（训练集 + 验证集）对 <span class="katex"><span class="katex-mathml"><math><semantics><mrow><mi>k</mi><mo>=</mo><mn>5</mn></mrow><annotation encoding="application/x-tex">k=5</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="strut" style="height:0.69444em;"></span><span class="strut bottom" style="height:0.69444em;vertical-align:0em;"></span><span class="base textstyle uncramped"><span class="mord mathit" style="margin-right:0.03148em;">k</span><span class="mrel">=</span><span class="mord mathrm">5</span></span></span></span> 的模型重新训练一遍。</li><li><strong>最终评估</strong>：使用一个 <strong>独立的测试集</strong>（从未参与过交叉验证的数据）对最终模型进行评估，得到最终的泛化性能。</li></ol><h3 id="目的" tabindex="-1">目的 <a class="header-anchor" href="#目的" aria-label="Permalink to &quot;目的&quot;">​</a></h3><p>交叉验证法，是划分数据集的一种方法，目的就是为了得到 <strong>更加准确可信的模型评分</strong>，减少因数据划分随机性带来的评估偏差。</p><h2 id="网格搜索" tabindex="-1">网格搜索 <a class="header-anchor" href="#网格搜索" aria-label="Permalink to &quot;网格搜索&quot;">​</a></h2><p>超参</p>',49)])])}const x=s(i,[["render",r]]);export{u as __pageData,x as default};
